class ProductionVerboseTree : Timber.Tree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val finalTag = tag ?: "Timber"
        if (message.length < 4000) {
            Log.println(priority, finalTag, message)
        } else {
            var i = 0
            while (i < message.length) {
                val end = (i + 4000).coerceAtMost(message.length)
                Log.println(priority, finalTag, message.substring(i, end))
                i = end
            }
        }
        if (t != null) {
            Log.println(priority, finalTag, Log.getStackTraceString(t))
        }
    }
}

class VerboseNetworkLoggingInterceptor : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val requestStartNs = System.nanoTime()

        logRequest(request)

        return try {
            val response = chain.proceed(request)
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - requestStartNs)
            logResponse(response, tookMs)
        } catch (e: Exception) {
            AppLogger.exception(
                e,
                message = "HTTP call failed",
                metadata = mapOf(
                    "url" to request.url.toString(),
                    "method" to request.method
                )
            )
            throw e
        }
    }

    private fun logRequest(request: Request) {
        val bodyString = requestBodyToString(request.body)
        AppLogger.apiRequest(
            method = request.method,
            url = request.url.toString(),
            headers = headersToMap(request.headers),
            body = bodyString
        )
    }

    private fun logResponse(response: Response, tookMs: Long): Response {
        val responseBody = response.body
        val source = responseBody?.source()
        source?.request(Long.MAX_VALUE)
        val buffer = source?.buffer?.clone()

        val bodyString = if (buffer != null && isPlaintext(buffer)) {
            val charset = responseBody.contentType().charset(Charsets.UTF_8) ?: Charsets.UTF_8
            buffer.readString(charset)
        } else {
            "[binary ${responseBody?.contentLength() ?: -1}-byte body omitted]"
        }

        AppLogger.apiResponse(
            code = response.code,
            url = response.request.url.toString(),
            headers = headersToMap(response.headers),
            body = bodyString,
            durationMs = tookMs
        )

        return response.newBuilder()
            .body(
                responseBody?.let {
                    ResponseBody.create(it.contentType(), bodyString.toByteArray(it.contentType().charset(Charsets.UTF_8) ?: Charsets.UTF_8))
                } ?: ResponseBody.create(null, ByteArray(0))
            )
            .build()
    }

    private fun requestBodyToString(requestBody: RequestBody?): String? {
        if (requestBody == null) return null
        return try {
            val buffer = Buffer()
            requestBody.writeTo(buffer)
            if (!isPlaintext(buffer)) {
                "[binary ${requestBody.contentLength()}-byte body omitted]"
            } else {
                val charset = requestBody.contentType().charset(Charsets.UTF_8) ?: Charsets.UTF_8
                buffer.readString(charset)
            }
        } catch (e: Exception) {
            AppLogger.exception(e, "Failed to read request body")
            "[unreadable body]"
        }
    }

    private fun headersToMap(headers: Headers): Map<String, String> {
        val map = LinkedHashMap<String, String>(headers.size)
        for (i in 0 until headers.size) {
            map[headers.name(i)] = headers.value(i)
        }
        return map
    }

    private fun isPlaintext(buffer: Buffer): Boolean {
        return try {
            val prefix = Buffer()
            val byteCount = if (buffer.size < 64) buffer.size else 64
            buffer.copyTo(prefix, 0, byteCount)
            for (i in 0 until 16) {
                if (prefix.exhausted()) break
                val codePoint = prefix.readUtf8CodePoint()
                if (Character.isISOControl(codePoint) && !Character.isWhitespace(codePoint)) {
                    return false
                }
            }
            true
        } catch (_: EOFException) {
            false
        }
    }

    private fun MediaType?.charset(default: Charset): Charset {
        return try {
            this?.charset(default) ?: default
        } catch (_: Exception) {
            default
        }
    }
}

object LoggingOkHttpFactory {
    fun create(base: OkHttpClient? = null): OkHttpClient {
        val builder = (base ?: OkHttpClient()).newBuilder()
        builder.addInterceptor(VerboseNetworkLoggingInterceptor())
        return builder.build()
    }
}

object DatabaseLogger {
    inline fun <T> logQuery(
        sql: String,
        args: List<Any?> = emptyList(),
        action: () -> T
    ): T {
        val start = System.nanoTime()
        return try {
            val result = action()
            val durationMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - start)
            val rowsAffected = when (result) {
                is Cursor -> result.count
                is Int -> result
                is Long -> result.toInt()
                is List<*> -> result.size
                else -> null
            }
            AppLogger.dbQuery(sql, args, durationMs, rowsAffected)
            if (result is Cursor) {
                AppLogger.dbQueryResult(sql, result, args)
            }
            result
        } catch (t: Throwable) {
            AppLogger.exception(
                t,
                message = "Database query failed",
                metadata = mapOf("sql" to sql, "args" to args)
            )
            throw t
        }
    }
}

object AuthLogger {
    fun logSuccess(
        username: String?,
        userId: String?,
        method: String? = null,
