    ) {
        AppLogger.authAttempt(
            username = username,
            success = true,
            userId = userId,
            method = method,
            metadata = metadata
        )
    }

    fun logFailure(
        username: String?,
        method: String? = null,
        failureReason: String? = null,
        metadata: Map<String, Any?> = emptyMap()
    ) {
        AppLogger.authAttempt(
            username = username,
            success = false,
            method = method,
            failureReason = failureReason,
            metadata = metadata
        )
    }

    inline fun <T> wrap(
        username: String?,
        method: String? = null,
        action: () -> T
    ): T {
        return try {
            val result = action()
            logSuccess(username = username, userId = null, method = method)
            result
        } catch (t: Throwable) {
            logFailure(
                username = username,
                method = method,
                failureReason = t.message
            )
            AppLogger.exception(
                t,
                message = "Authentication failed",
                metadata = mapOf("username" to username, "method" to method)
            )
            throw t
        }
    }
}

